solutions.cpp:
import <iostream>
#include <cmath>
#include <vector>

using namespace std;
class Solution {
public:
    int solve(vector<int> &nums) {
        int sum = 0;
        for (int i = 0; i < nums.size(); i++) {
            sum += sqrt(nums[i]);
        }
        return (int)(sum);
    }
};

int main() {
    ios_base::sync_with_stdio(false); cin.tie(0);
    Solution solution;
    int n;
    cin >> n;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) {
        cin >> nums[i];
    }
    cout << solution.solve(nums) << endl;
    return 0;
}
